@Composable fun ProfileScreen( viewModel: HabitViewModel, onBack: () -> Unit, onStatisticsClick: () -> Unit, onPrivacyClick: () -> Unit ) { val context = LocalContext.current val profile by viewModel.userProfile.collectAsStateWithLifecycle() val habits by viewModel.habits.collectAsStateWithLifecycle() val cardShape = RoundedCornerShape(22.dp) val subtleBorder = BorderStroke(1.dp, BorderSubtle)
Box( modifier = Modifier .fillMaxSize() .background(BackgroundDeep) .padding(horizontal = 24.dp, vertical = 24.dp), contentAlignment = Alignment.TopCenter ) { Column( modifier = Modifier .widthIn(max = 520.dp) .fillMaxWidth() .verticalScroll(rememberScrollState()) ) { Row( modifier = Modifier.fillMaxWidth(), verticalAlignment = Alignment.CenterVertically ) { Surface( shape = RoundedCornerShape(12.dp), color = SurfaceCard, border = subtleBorder ) { IconButton(onClick = onBack) { Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Volver", tint = TextPrimary) } } Text( text = "Mi Perfil", color = TextPrimary, style = MaterialTheme.typography.titleLarge, modifier = Modifier.padding(start = 10.dp) ) }
Spacer(modifier = Modifier.height(24.dp))
Column(horizontalAlignment = Alignment.CenterHorizontally, modifier = Modifier.fillMaxWidth()) { Box( modifier = Modifier .size(84.dp) .clip(CircleShape) .background(Brush.linearGradient(listOf(AccentPurple, AccentGreen))) .border(2.dp, AccentGreen.copy(alpha = 0.5f), CircleShape), contentAlignment = Alignment.Center ) { UserAvatarImage( imageUri = profile.imageUri, modifier = Modifier .fillMaxSize() .clip(CircleShape) ) }
Spacer(modifier = Modifier.height(14.dp)) Text(text = profile.name, color = TextPrimary, style = MaterialTheme.typography.headlineLarge) Text(text = profile.email, color = TextSecondary, style = MaterialTheme.typography.bodyMedium) Surface( modifier = Modifier.padding(top = 10.dp), color = AccentGreen.copy(alpha = 0.12f), shape = RoundedCornerShape(20.dp) ) { Text( text = "⭐ Premium", color = AccentGreen, fontWeight = FontWeight.Bold, modifier = Modifier.padding(horizontal = 14.dp, vertical = 6.dp) ) } }
Spacer(modifier = Modifier.height(22.dp))
Row(horizontalArrangement = Arrangement.spacedBy(10.dp), modifier = Modifier.fillMaxWidth()) { StatCard( modifier = Modifier.weight(1f), value = profile.habitsCompleted, label = "Completados", shape = cardShape, border = subtleBorder ) StatCard( modifier = Modifier.weight(1f), value = profile.currentStreak, label = "Racha ", shape = cardShape, border = subtleBorder ) StatCard( modifier = Modifier.weight(1f), value = habits.size, label = "Hábitos", shape = cardShape, border = subtleBorder ) }
Spacer(modifier = Modifier.height(22.dp)) Text(text = "Configuración", color = TextPrimary, style = MaterialTheme.typography.titleLarge) Spacer(modifier = Modifier.height(12.dp))
Card( shape = cardShape, colors = CardDefaults.cardColors(containerColor = SurfaceCard), border = subtleBorder ) { ListItem( headlineContent = { Text("Notificaciones", color = TextPrimary) }, supportingContent = { Text("Recordatorios activos", color = TextSecondary) }, leadingContent = { Icon(Icons.Default.Notifications, contentDescription = null, tint = AccentGreen) }, trailingContent = { Switch( checked = profile.notificationsEnabled, onCheckedChange = viewModel::setNotificationsEnabled, colors = SwitchDefaults.colors( checkedThumbColor = BackgroundDeep, checkedTrackColor = AccentGreen, uncheckedThumbColor = Color(0xFF555555), uncheckedTrackColor = Color(0xFF2A2A2A) ) ) } ) HorizontalDivider(color = BorderSubtle) ListItem( headlineContent = { Text("Modo claro", color = TextPrimary) }, supportingContent = { Text("Se mantiene guardado en la app", color = TextSecondary) }, leadingContent = { Icon(Icons.Default.WbSunny, contentDescription = null, tint = AccentOrange) }, trailingContent = { Switch( checked = !profile.darkModeEnabled, onCheckedChange = { enabled -> val darkModeEnabled = !enabled viewModel.setDarkModeEnabled(darkModeEnabled) UserLocalStorage.saveDarkModeEnabled(context, darkModeEnabled) }, colors = SwitchDefaults.colors( checkedThumbColor = BackgroundDeep, checkedTrackColor = AccentGreen, uncheckedThumbColor = Color(0xFF555555), uncheckedTrackColor = Color(0xFF2A2A2A) ) ) } ) HorizontalDivider(color = BorderSubtle) SettingsChevronItem( icon = Icons.Default.BarChart, iconTint = Color(0xFFFB923C), label = "Estadísticas", description = "Ver historial completo", onClick = onStatisticsClick ) HorizontalDivider(color = BorderSubtle) SettingsChevronItem( icon = Icons.Default.Lock, iconTint = Color(0xFF60A5FA), label = "Privacidad", description = "Gestionar datos", onClick = onPrivacyClick ) HorizontalDivider(color = BorderSubtle) ListItem( headlineContent = { Text("Cerrar sesión", color = DangerRed) }, supportingContent = { Text("Hasta pronto ", color = TextSecondary) }, leadingContent = { Icon(Icons.Default.DeleteOutline, contentDescription = null, tint = DangerRed) }, trailingContent = { Icon(Icons.Default.ChevronRight, contentDescription = null, tint = TextSecondary) } ) } } } }
@Composable private fun StatCard( modifier: Modifier = Modifier, value: Int, label: String, shape: RoundedCornerShape, border: BorderStroke ) { val animatedValue by animateIntAsState(targetValue = value, animationSpec = tween(800), label = "statValue")
Card( modifier = modifier, shape = shape, colors = CardDefaults.cardColors(containerColor = SurfaceCard), border = border ) { Column( modifier = Modifier.padding(vertical = 16.dp, horizontal = 10.dp), horizontalAlignment = Alignment.CenterHorizontally ) { Text(text = animatedValue.toString(), color = AccentGreen, style = MaterialTheme.typography.headlineLarge) Text(text = label, color = TextSecondary, style = MaterialTheme.typography.labelMedium) } } }
@Composable private fun SettingsChevronItem( icon: androidx.compose.ui.graphics.vector.ImageVector, iconTint: Color, label: String, description: String, onClick: () -> Unit ) { ListItem( modifier = Modifier.clickable(onClick = onClick), headlineContent = { Text(label, color = TextPrimary) }, supportingContent = { Text(description, color = TextSecondary) }, leadingContent = { Icon(icon, contentDescription = null, tint = iconTint) }, trailingContent = { Icon(Icons.Default.ChevronRight, contentDescription = null, tint = TextSecondary) } ) }
@Preview(uiMode = Configuration.UI_MODE_NIGHT_YES, showBackground = true) @Composable private fun ProfilePreview() { HabitFlowTheme { ProfileScreen( viewModel = HabitViewModel(), onBack = {}, onStatisticsClick = {}, onPrivacyClick = {} ) } }

package ni.edu.uam.myhabitsapp.ui.navigation

import androidx.compose.animation.fadeIn
import androidx.compose.animation.fadeOut
import androidx.compose.animation.slideInHorizontally
import androidx.compose.animation.core.tween
import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import ni.edu.uam.myhabitsapp.ui.DashboardScreen
import ni.edu.uam.myhabitsapp.ui.HabitViewModel
import ni.edu.uam.myhabitsapp.ui.LoginScreen
import ni.edu.uam.myhabitsapp.ui.ProfileScreen
import ni.edu.uam.myhabitsapp.ui.StatisticsScreen
import androidx.lifecycle.viewmodel.compose.viewModel

sealed class Screen(val route: String) {
    data object Login : Screen("login")
    data object Dashboard : Screen("dashboard")
    data object Profile : Screen("profile")
    data object Statistics : Screen("statistics")
}

@Composable
fun AppNavigation(viewModel: HabitViewModel = viewModel()) {
    val navController = rememberNavController()

    NavHost(
        navController = navController,
        startDestination = Screen.Login.route,
        enterTransition = {
            fadeIn(tween(300)) + slideInHorizontally(tween(300)) { fullWidth -> fullWidth / 4 }
        },
        exitTransition = { fadeOut(tween(300)) },
        popEnterTransition = {
            fadeIn(tween(300)) + slideInHorizontally(tween(300)) { fullWidth -> -fullWidth / 4 }
        },
        popExitTransition = { fadeOut(tween(300)) }
    ) {
        composable(Screen.Login.route) {
            LoginScreen(
                viewModel = viewModel,
                onLogin = {
                    navController.navigate(Screen.Dashboard.route) {
                        popUpTo(Screen.Login.route) { inclusive = true }
                    }
                }
            )
        }
        composable(Screen.Dashboard.route) {
            DashboardScreen(
                viewModel = viewModel,
                onProfileClick = { navController.navigate(Screen.Profile.route) }
            )
        }
        composable(Screen.Profile.route) {
            ProfileScreen(
                viewModel = viewModel,
                onBack = { navController.popBackStack() },
                onStatisticsClick = { navController.navigate(Screen.Statistics.route) }
            )
        }
        composable(Screen.Statistics.route) {
            StatisticsScreen(
                viewModel = viewModel,
                onBack = { navController.popBackStack() }
            )
        }
    }
}

